@keyframes reality-fadeOut {
  from { opacity: 1; visibility: visible; }
  to { opacity: 0; visibility: hidden; }
}

@keyframes reality-fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes reality-blink {
  0%, 49% { opacity: 1; }
  50%, 100% { opacity: 0; }
}

@keyframes reality-grow {
  from { width: 0; }
  to { width: 100%; }
}

@keyframes reality-scan {
  0% { top: 0; opacity: 0.25; }
